SELECT total_area
  FROM watersheds
  WHERE watershed_id = 0;

SELECT watershed_name, total_area
FROM watersheds
ORDER BY total_area DESC;

SELECT watershed_name
FROM watersheds
WHERE location = 'Athens, GA, USA';

SELECT watershed_name
FROM watersheds
WHERE total_area = (SELECT MAX(total_area) FROM watersheds);

SELECT wetland_name
FROM wetland_types
WHERE wetland_id = 0;

SELECT type_name, description
FROM land_use_types
WHERE category_id = 1;
